import React, { useState, useEffect } from "react";
import { NavLink } from "react-router-dom";
import { getAllUsers, deleteUser, updateUser } from "../../service/apiservice";
import "./RegUser.css";

const RegisteredUsers = () => {
  const [users, setUsers] = useState([]);
  const [searchphone, setSearchphone] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  /* ==============================
     FETCH USERS FROM DATABASE
  ============================== */
  const fetchUsers = async () => {
    try {
      setLoading(true);
      const data = await getAllUsers();
      console.log("API Response:", data);

      // Ensure users is always an array
      if (Array.isArray(data)) {
        setUsers(data);
      } else if (Array.isArray(data?.users)) {
        setUsers(data.users);
      } else {
        setUsers([]);
      }

      setError("");
    } catch (error) {
      console.error(error);
      setError("Failed to load users");
      setUsers([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

 /* ==============================
   DELETE USER BY PHONE
============================== */
/* ==============================
   DELETE USER
============================== */
const handleDelete = async (phone) => {
  const confirmDelete = window.confirm(
    "Are you sure you want to delete this user?"
  );

  if (!confirmDelete) return;

  try {
    await deleteUser(phone);   // ✅ use apiservice function
    alert("User deleted successfully ✅");
    fetchUsers();              // refresh table
  } catch (err) {
    console.error("Delete Error:", err);
    alert(err?.message || "Failed to delete user ❌");
  }
};
  /* ==============================
     UPDATE USER (PROMPT STYLE)
  ============================== */
  const handleUpdate = async (user) => {

    const name = window.prompt("Enter Name:", user.name);
    if (name === null) return;

    const username = window.prompt("Enter Username:", user.username);
    if (username === null) return;

    const email = window.prompt("Enter Email:", user.email);
    if (email === null) return;

    const phone = window.prompt("Enter Phone:", user.phone);
    if (phone === null) return;

    const password = window.prompt("Enter Password:", user.password);
    if (password === null) return;

    const confirmUpdate = window.confirm(
      "Are you sure you want to update this user?"
    );

    if (!confirmUpdate) return;

    try {
      await updateUser(user.phone, {
        name,
        username,
        email,
        phone,
        password,
      });

      alert("User updated successfully ✅");
      fetchUsers();
    } catch (err) {
      console.error(err);
      alert("Failed to update user ❌");
    }
  };

  /* ==============================
     SAFE SEARCH FILTER
  ============================== */
  const filteredUsers = Array.isArray(users)
    ? users.filter((user) =>
        user.phone
          ?.toString()
          .toLowerCase()
          .includes(searchphone.toLowerCase())
      )
    : [];

  return (
    <div className="dashboard-container">
      {/* ================= Sidebar ================= */}
      <aside className="sidebar">
        <h2 className="brand">Accident Admin</h2>
        <ul className="nav-list">
        
                  <NavLink to="/RegUser" className="nav-item">
                    <li>Registered Users</li>
                  </NavLink>
        
                  <NavLink to="/AccidentReport" className="nav-item">
                    <li>Accident Reports</li>
                  </NavLink>
        
                  <NavLink to="/LiveAlerts" className="nav-item">
                    <li>Live Alerts</li>
                  </NavLink>
        
                  <NavLink to="/Emergency" className="nav-item">
                    <li>Emergency Services</li>
                  </NavLink>
        
                  <NavLink to="/Mlprediction" className="nav-item">
                    <li>ML Predictions</li>
                  </NavLink>
        
                  {/* ✅ Counselor option added */}
                  <NavLink to="/Counselor" className="nav-item">
                    <li>Counselor Management</li>
                  </NavLink>
        
                  <NavLink to="/Feedback" className="nav-item">
                    <li>Feedback</li>
                  </NavLink>
        
                  <NavLink to="/Settings" className="nav-item">
                    <li>Settings</li>
                  </NavLink>
                </ul>
              </aside>

      {/* ================= Main Content ================= */}
      <div className="content-area">
        <header className="top-header">
          <h1>Registered Users</h1>
        </header>

        {/* ================= Search ================= */}
        <div className="search-container">
          <input
            type="text"
            placeholder="Search by User phone..."
            value={searchphone}
            onChange={(e) => setSearchphone(e.target.value)}
          />
        </div>

        {/* ================= Table ================= */}
        <div className="table-card">
          {loading ? (
            <p style={{ textAlign: "center" }}>Loading users...</p>
          ) : error ? (
            <p style={{ textAlign: "center", color: "red" }}>{error}</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Name</th>
                  <th>UserName</th>
                  <th>Email</th>
                  <th>Phone</th>
                  <th>Password</th>
                  <th>Actions</th>
                </tr>
              </thead>

              <tbody>
                {filteredUsers.length > 0 ? (
                  filteredUsers.map((user) => (
                    <tr key={user.phone}>
                      <td>{user.name}</td>
                      <td>{user.username}</td>
                      <td>{user.email}</td>
                      <td>{user.phone}</td>
                      <td>********</td>
                      <td className="action-btns">
                        <button
                          className="edit"
                          onClick={() => handleUpdate(user)}
                        >
                          Edit
                        </button>

                        <button
                          className="delete"
                          onClick={() => handleDelete(user.phone)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="6" style={{ textAlign: "center" }}>
                      No users found
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default RegisteredUsers;
